import {
  Box,
  Breadcrumbs,
  Button,
  FormControl,
  Grid,
  InputLabel,
  MenuItem,
  Select,
  Typography,
} from '@material-ui/core';
import { makeStyles } from '@material-ui/styles';
import AddIcon from '@material-ui/icons/Add';
import CreateIcon from '@material-ui/icons/Create';
import React from 'react';
import { useTranslation } from 'react-i18next';
import styled from 'styled-components';
import { Layout } from '../components/Layout';
import { Link } from 'react-router-dom';
import { ProductCatalogDataTable } from '../components/PorductCatalogDataTable';

const useStyles = makeStyles(() => ({
  formControl: {
    minWidth: 120,
  },
  select: {},
  label: {},
}));

const ProductCatalog = () => {
  const { t } = useTranslation();
  const classes = useStyles();
  const [age, setAge] = React.useState('');

  const handleChange = (event) => {
    setAge(event.target.value);
  };

  return (
    <Layout
      title={
        <Breadcrumbs aria-label="breadcrumb">
          <Typography display="initial">Product Catalog</Typography>
        </Breadcrumbs>
      }
    >
      <Header>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          color="primary"
          style={{ marginRight: 10 }}
        >
          Add Product
        </Button>
        <Button variant="contained">Delete Product</Button>
        <FormControl
          style={{ marginLeft: 20, width: 200 }}
          variant="outlined"
          className={classes.formControl}
          size="small"
        >
          <InputLabel id="demo-simple-select-label" className={classes.label}>
            Age
          </InputLabel>
          <Select
            className={classes.select}
            labelId="demo-simple-select-label"
            id="demo-simple-select"
            value={age}
            onChange={handleChange}
            label="Age"
          >
            <MenuItem value={10}>Ten</MenuItem>
            <MenuItem value={20}>Twenty</MenuItem>
            <MenuItem value={30}>Thirty</MenuItem>
          </Select>
        </FormControl>
      </Header>

      <Box marginTop={3} />

      <Grid container direction="column" spacing={2} wrap="nowrap">
        <Grid item xs>
          <ProductCatalogDataTable
            dataIndex="id"
            resource_url=""
            columns={[
              { label: 'PID', key: 'PID' },
              { label: 'Image', key: 'Image' },
              { label: 'Product Name', key: 'Product Name' },
              { label: 'Price', key: 'Price' },
              { label: 'Brand', key: 'Brand' },
              {
                label: t('brand_details.status'),
                key: 'is_active',
                content: ({ is_active }) =>
                  is_active
                    ? t('brand_details.active')
                    : t('brand_details.inactive'),
              },
              {
                label: 'Modification',
                content: ({ id }) => (
                  <Link
                    to={'/product-catalog/edit'}
                    style={{ textDecoration: 'none' }}
                  >
                    <Button
                      startIcon={<CreateIcon />}
                      variant="contained"
                      color="primary"
                    >
                      Edit
                    </Button>
                  </Link>
                ),
              },
            ]}
            toolbar={{
              export: true,
            }}
          />
        </Grid>
      </Grid>
    </Layout>
  );
};

export default ProductCatalog;

const Header = styled.div`
  margin-top: -146px;
  margin-bottom: 100px;
`;
